import struct, zlib, re

def read_pdf_text\(path\):
    with open\(path, 'rb'\) as f:
        data = f.read\(\)
    # Extract text between BT and ET markers
    texts = []
    # Find all Tj and TJ operators
    pattern = re.compile\(rb'\\\(\([^\)]*\)\\\)\\s*Tj|\\[\([^\\]]*\)\\]\\s*TJ'\)
    for m in pattern.finditer\(data\):
        if m.group\(1\):
            try:
                texts.append\(m.group\(1\).decode\('latin-1'\)\)
            except:
                pass
        elif m.group\(2\):
            inner = m.group\(2\)
            parts = re.findall\(rb'\\\(\([^\)]*\)\\\)', inner\)
            for p in parts:
                try:
                    texts.append\(p.decode\('latin-1'\)\)
                except:
                    pass
    return ' '.join\(texts\)

